sp_widget.client_script:
api.controller = function($scope,spUtil,mandatoryValidator,$rootScope,spModal,$location) {
  var c = this;

  c.showForm = false;


	/* INIT OPERATOR */
  c.setDefaultOperator = function() {

    if (!c.data.rules) return;

    c.data.rules.forEach(function(rule) {
      if (!rule.operator) {
        rule.operator = "+"; 
      }
    });
  };

		c.editRecord = function(rulesysid)
	{
			var url="?id=incentnow_form&table=x_ctans_incentnow_lookup_rule&sys_id="+rulesysid;
			$location.url(url);

	}
		c.editPayoutRecord = function(payoutysid)
	{

		var url ="?id=incentnow_form&table=x_ctans_incentnow_payout_summary&sys_id="+payoutysid;
	$location.url(url);
		}

  /* CALL ON LOAD */
  c.setDefaultOperator();

	/* GET CONDITIONS */
c.getConditions = function(rule) {
  if (!rule || !rule.conditions)
    return [];

  return rule.conditions.split(',');
};

/* DELETE PAYOUT */
c.deletePayout = function(sys_id) {

  if (!confirm("Delete this rule?"))
    return;

  c.server.get({
    action: 'deletePayout',
    sys_id: sys_id
  }).then(function() {
    spUtil.update($scope);
  });
};

			c.deleteRecord= function(rulesysid,reqtable)
			{

					c.data.action="deleteRecord";
					c.data.rulesysid= rulesysid;
					c.data.reqtable=reqtable;
				//alert(reqtable);

					spModal.open({
					title: 'Delete Confirmation',
					message: 'This action cannot be undone. Are you sure?',
					buttons: [
							{label: 'Cancel', cancel: true},
							{label: 'Delete', primary: true}
					]
					}).then(function() {
					 c.server.update().then(function(response){

									if(response.status==true)
											{
												spUtil.addInfoMessage("Record deleted successfully.");
												spUtil.update($scope);
											}

											//spUtil.addErrorMessage("No Authorization to perform the action");
										});
									});
					};



  c.openForm = function() {
    c.showForm = true;
  };

  c.cancel = function() {
    c.showForm = false;
  };

	c.cancelPayout= function()
	{
		c.showPayoutForm=false;
	};

  c.addStep = function() {

	var result = mandatoryValidator.validate(c.data.f);
	if (!result.valid) {
            spUtil.addErrorMessage(result.message);
            return;
        } 

    c.data.action = "addStep";
    c.data.form = c.data.f;
		c.isSaving=true;

    c.server.update().then(function(res) {
      c.steps = res.steps;
      c.showForm = false;
			c.isSaving=false;

			$rootScope.$broadcast('summary.refresh');
    });
  };

	c.addPayoutRule= function()
	{
			var backup = angular.copy(c.data.payoutsummary);
			var result = mandatoryValidator.validate(c.data.payoutsummary);
			if (!result.valid) {
            spUtil.addErrorMessage(result.message);
            return;
        } 
		c.data.action="addPayout";
		c.data.payoutform=c.data.payoutsummary;
		c.isPayout=true;
		c.server.update().then(function(res) {

			if(res.status)
			{c.showPayoutForm=false;
			c.setDefaultOperator();			
			$rootScope.$broadcast('summary.refresh');}
			else
				{
					c.data.payoutsummary = backup;
				}
		c.isPayout=false;	
		});


	};

  c.deleteStep = function(sys_id) {

    c.data.action = "deleteStep";
    c.data.sys_id = sys_id;

    c.server.update().then(function(res) {
      c.steps = res.steps;
    });
  };

	// PHASE 2 ONLY
c.showPayoutForm = false;

c.payoutRule = {
  name: "",
  items: []
};

c.openPayoutForm = function() {
  c.showPayoutForm = true;

  c.payoutRule = {
    name: "",
    items: [{}]
  };
};

c.cancelPayoutForm = function() {
  c.showPayoutForm = false;
};

c.addPayoutInput = function() {
  c.payoutRule.items.push({});
};

c.savePayoutRule = function() {

  var result = 0;

  c.payoutRule.items.forEach(function(item, i) {
    var val = parseFloat(item.value) || 0;

    if (i === 0) result = val;
    else {
      var prevOp = c.payoutRule.items[i - 1].operator;

      if (prevOp === "+") result += val;
      if (prevOp === "-") result -= val;
      if (prevOp === "*") result *= val;
      if (prevOp === "/") result /= val;
    }
  });

  c.payoutRule.result = result;

  c.rules.push(angular.copy(c.payoutRule));

  c.showPayoutForm = false;
};

  // INIT
  c.steps = c.data.steps || [];
};

sp_widget.css:
.rule-actions {
  display: flex;
  gap: 8px;
  align-items: center;
}

.action-icon svg {
  width: 16px;
  height: 16px;
  display: block;
}

.action-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  height: 32px;
  padding: 0 12px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 500;
  line-height: 1.2;
  white-space: nowrap;
  box-shadow: none;
}

.action-btn:focus,
.action-btn:active:focus {
  outline: none;
  box-shadow: 0 0 0 3px rgba(81, 163, 255, 0.25);
}


.action-btn-ghost {
  background: transparent;
  border: 1px solid transparent;
  color: #111827;
}

.action-btn-ghost:hover,
.action-btn-ghost:focus {
  background: #f3f4f6;
  /*color: #111827; */
}

.delete-icon
{
color: red;
}


.dg-wrapper {
  margin-top: 20px;
}

.dg-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.dg-header h3 {
