sp_widget.script:
(function() {

  data.table = $sp.getParameter('table');
  data.plansysid = $sp.getParameter('sys_id') || "-1";
  data.isEarningRuleExist = isEarningRuleExist();

  function isEarningRuleExist() {
    var gEarning = new GlideRecordSecure('x_ctans_incentnow_earning_rule');
    gEarning.addQuery("plan" , data.plansysid);
    gEarning.query();
    if (gEarning.hasNext()) return "1";
    return "-1";
  }

  var table = "x_ctans_incentnow_lookup_rule";

  // LOAD FORM
  data.f = $sp.getForm(table, "-1", '', 'default');
	data.payoutsummary=$sp.getForm('x_ctans_incentnow_payout_summary',"-1",'','default');

	data.f=new x_ctans_incentnow.IncentNowPortalUtils().applyPlaceholders(data.f);
	data.payoutsummary=new x_ctans_incentnow.IncentNowPortalUtils().applyPlaceholders(data.payoutsummary);


	//gs.addErrorMessage(data.payoutsummary);
  setPolicies(data.f);
	setPolicies(data.payoutsummary);

	//gs.addErrorMessage(data.f._fields);
  function setPolicies(formJson) {
    if (data.plansysid && formJson && formJson._fields && formJson._fields.plan) {

      var planGR = new GlideRecordSecure('x_ctans_incentnow_plan'); 
      if (planGR.get(data.plansysid)) {

        formJson._fields.plan.value = data.plansysid;
        formJson._fields.plan.displayValue = planGR.getDisplayValue();

      }
    }
  }


  if (input && input.action == "addStep") {

    if (!input.form || !input.form._fields) {
      gs.addErrorMessage("Form data missing");
      return;
    }

    var fields = input.form._fields;
		insertRecords(table,fields);

  }

	if (input && input.action == "addPayout") {

    if (!input.payoutform || !input.payoutform._fields) {
      gs.addErrorMessage("Form data missing");
      return;
    }

    var fields = input.payoutform._fields;
		insertRecords("x_ctans_incentnow_payout_summary",fields);

  }

	function insertRecords(table, fields) {
  try {
    var grNew = new GlideRecordSecure(table);
    grNew.initialize();

    for (var key in fields) {
      if (fields[key].value !== undefined) {
        grNew.setValue(key, fields[key].value);
      }
    }

    var sysId = grNew.insert();

    if (gs.nil(sysId)) {
      data.status = false;
      data.error = "Insert failed (no sys_id returned)";
    } else {
      data.status = true;
      data.sys_id = sysId;
    }

  } catch (e) {
    data.status = false;
    data.error = e.message;
  }
}

  // DELETE
  if (input && input.action == "deleteStep") {
    var grDel = new GlideRecordSecure(table);
    if (grDel.get(input.sys_id)) {
      grDel.deleteRecord();
    }
  }
	if(input && input.action=="deleteRecord")
		{
			try{
				var grearning = new GlideRecordSecure(input.reqtable);
				grearning.addQuery("sys_id",input.rulesysid);
				grearning.query();
				//gs.addErrorMessage(grearning.getEncodedQuery());
			if(grearning.next())
				{
					//gs.addErrorMessage("testing");
					data.status=grearning.deleteRecord();
				}
			}
			catch(e)
				{
					gs.addErrorMessage(e.message);
				}



		}

	//Fetch Fields Keys

var allowedFields = getFormTableFields("x_ctans_incentnow_lookup_rule");
		function getFormTableFields(tableName)
	{data.lookupData = [];

    var table = '';

    data.tableForm = $sp.getForm(tableName, "-1", '', 'default');

    if (data.tableForm && data.tableForm._fields) {

        Object.keys(data.tableForm._fields).forEach(function(fieldName) {

            data.lookupData.push({
                key: fieldName
            });

        });

    }
	return data.lookupData;
	}



			/* FETCH PAYOUT RULES */
		data.rules = [];

		var payoutGR = new GlideRecordSecure('x_ctans_incentnow_payout_summary');
		payoutGR.addQuery("plan" , data.plansysid);
		payoutGR.orderBy("sys_created_on");
		payoutGR.query();

		while (payoutGR.next()) {

			data.rules.push({
				sys_id: payoutGR.getUniqueValue(),
				name: payoutGR.getDisplayValue('rule_name'),
				payout: payoutGR.getValue('output_unit'), // use value for number
				conditions: getPayoutSummary(payoutGR.getUniqueValue()),//payoutGR.getValue('payout_type')
				payout_type: payoutGR.getValue('payout_type')
			});

		}

	function getPayoutSummary(sysid)
	{
				var grPayout= new GlideRecordSecure("x_ctans_incentnow_payout_summary");
				if(grPayout.get(sysid))
					{
						var input1=new x_ctans_incentnow.IncentNowPayoutEngine().resolveSummaryInput(grPayout,'1','','');
						input1=input1.trace[0].name;


						var input2=new x_ctans_incentnow.IncentNowPayoutEngine().resolveSummaryInput(grPayout,'2','','');
						input2=input2.trace[0].name;

						var operator=grPayout.operator;
						if(operator=="subtract" || operator=="Subtract")
						{
							operator=" - ";
						}
						if(operator=="divide" || operator=="Divide")
						{
							operator=" ÷ ";
						}
						if(operator=="add" || operator=="Add")
						{
							operator=" + ";
						}
						if(operator=="multiply" || operator=="Multiply")
						{
							operator=" x ";
						}

						return input1+operator+input2;
					}

	}




    data.elements = [{element:'sys_id',label:"Sys Id"}];

    var grDic = new GlideRecordSecure('sys_dictionary'); // lookup rule table fields
		grDic.addEncodedQuery("name=x_ctans_incentnow_lookup_rule^elementNOT LIKEsys_^element!=active");
    grDic.query();

    while (grDic.next()) {

        data.elements.push({
            element: grDic.getValue('element'),
						label:grDic.getValue('column_label')
        });
    }



  data.steps = [];

  var grTab = new GlideRecordSecure(table);
  grTab.addQuery("plan" ,data.plansysid);
  grTab.orderBy("sys_created_on");
  grTab.query();

  while (grTab.next()) {

		var obj={};
		for(var i=0;i<data.elements.length;i++)
			{
				if(grTab.getDisplayValue(data.elements[i].element))
				obj[data.elements[i].element]=grTab.getDisplayValue(data.elements[i].element);
			}


		data.steps.push(obj);

  }


})();
